import type { Quiz } from './types/quiz';
import { renderHomeScreen } from './components/home-screen';
import { renderQuizPlayer } from './components/quiz-player';
import { renderResultsScreen, calculateResult, saveResult } from './components/results-screen';

/**
 * Initialize the application and mount it to the given root element.
 * Manages navigation between home, quiz player, and results screens.
 */
export function createApp(root: HTMLElement): void {
  showHome(root);
}

function showHome(root: HTMLElement): void {
  root.innerHTML = '';
  renderHomeScreen(root, (quiz: Quiz) => {
    showQuiz(root, quiz);
  });
}

function showQuiz(root: HTMLElement, quiz: Quiz): void {
  root.innerHTML = '';
  renderQuizPlayer(
    root,
    quiz,
    (answers: Record<string, string>) => {
      const result = calculateResult(quiz, answers);
      saveResult(result);
      showResults(root, quiz, result);
    },
    () => { showHome(root); },
  );
}

function showResults(root: HTMLElement, quiz: Quiz, result: ReturnType<typeof calculateResult>): void {
  root.innerHTML = '';
  renderResultsScreen(
    root,
    quiz,
    result,
    () => { showQuiz(root, quiz); },
    () => { showHome(root); },
  );
}
