import type { Quiz, QuizResult } from '../types/quiz';
import { save, load } from '../storage/local-storage';

/** Callback to replay the same quiz. */
export type OnReplay = () => void;

/** Callback to return to home screen. */
export type OnGoHome = () => void;

/**
 * Calculate the quiz result from the user's answers.
 */
export function calculateResult(quiz: Quiz, answers: Record<string, string>): QuizResult {
  let score = 0;

  for (const question of quiz.questions) {
    const selectedId = answers[question.id];
    const correct = question.answers.find((a) => a.isCorrect);
    if (selectedId === correct?.id) {
      score++;
    }
  }

  return {
    quizId: quiz.id,
    score,
    totalQuestions: quiz.questions.length,
    answers,
    completedAt: Date.now(),
  };
}

/**
 * Save a quiz result to local storage history.
 */
export function saveResult(result: QuizResult): void {
  const history = load<QuizResult[]>('results') ?? [];
  history.push(result);
  save('results', history);
}

/**
 * Load all quiz results from local storage.
 */
export function loadResults(): QuizResult[] {
  return load<QuizResult[]>('results') ?? [];
}

/**
 * Render the results screen showing the score and breakdown.
 */
export function renderResultsScreen(
  container: HTMLElement,
  quiz: Quiz,
  result: QuizResult,
  onReplay: OnReplay,
  onGoHome: OnGoHome,
): void {
  container.innerHTML = '';

  const wrapper = document.createElement('div');
  wrapper.className = 'results-screen';

  // Score header
  const header = document.createElement('header');
  header.className = 'results-header';

  const percentage = Math.round((result.score / result.totalQuestions) * 100);
  const grade = getGrade(percentage);

  const scoreCircle = document.createElement('div');
  scoreCircle.className = `results-score-circle ${grade.className}`;
  scoreCircle.textContent = `${String(percentage)}%`;

  const scoreLabel = document.createElement('p');
  scoreLabel.className = 'results-score-label';
  scoreLabel.textContent = `${String(result.score)} z ${String(result.totalQuestions)} správně`;

  const gradeText = document.createElement('p');
  gradeText.className = `results-grade ${grade.className}`;
  gradeText.textContent = grade.label;

  header.appendChild(scoreCircle);
  header.appendChild(scoreLabel);
  header.appendChild(gradeText);

  // Question breakdown
  const breakdown = document.createElement('section');
  breakdown.className = 'results-breakdown';

  const breakdownTitle = document.createElement('h3');
  breakdownTitle.className = 'results-breakdown-title';
  breakdownTitle.textContent = 'Přehled odpovědí';
  breakdown.appendChild(breakdownTitle);

  for (const question of quiz.questions) {
    const selectedId = result.answers[question.id];
    const correctAnswer = question.answers.find((a) => a.isCorrect);
    const isCorrect = selectedId === correctAnswer?.id;

    const row = document.createElement('div');
    row.className = `results-row ${isCorrect ? 'correct' : 'wrong'}`;

    const icon = document.createElement('span');
    icon.className = 'results-row-icon';
    icon.textContent = isCorrect ? '+' : '-';

    const questionText = document.createElement('span');
    questionText.className = 'results-row-question';
    questionText.textContent = question.question;

    row.appendChild(icon);
    row.appendChild(questionText);

    if (!isCorrect && correctAnswer) {
      const correctText = document.createElement('span');
      correctText.className = 'results-row-correct';
      correctText.textContent = correctAnswer.text;
      row.appendChild(correctText);
    }

    breakdown.appendChild(row);
  }

  // Actions
  const actions = document.createElement('div');
  actions.className = 'results-actions';

  const replayBtn = document.createElement('button');
  replayBtn.className = 'btn btn-primary';
  replayBtn.textContent = 'Zkusit znovu';
  replayBtn.addEventListener('click', onReplay);

  const homeBtn = document.createElement('button');
  homeBtn.className = 'btn btn-ghost';
  homeBtn.textContent = 'Zpět na úvod';
  homeBtn.addEventListener('click', onGoHome);

  actions.appendChild(replayBtn);
  actions.appendChild(homeBtn);

  wrapper.appendChild(header);
  wrapper.appendChild(breakdown);
  wrapper.appendChild(actions);

  container.appendChild(wrapper);
}

interface Grade {
  label: string;
  className: string;
}

function getGrade(percentage: number): Grade {
  if (percentage >= 90) return { label: 'Výborně!', className: 'grade-excellent' };
  if (percentage >= 75) return { label: 'Chvalitebně!', className: 'grade-good' };
  if (percentage >= 50) return { label: 'Dobře', className: 'grade-ok' };
  if (percentage >= 30) return { label: 'Dostatečně', className: 'grade-poor' };
  return { label: 'Nedostatečně', className: 'grade-fail' };
}
