const STORAGE_PREFIX = 'featcher_';

/** Save a value to local storage under the app prefix. */
export function save<T>(key: string, value: T): void {
  const prefixedKey = STORAGE_PREFIX + key;
  const serialized = JSON.stringify(value);
  localStorage.setItem(prefixedKey, serialized);
}

/** Load a value from local storage. Returns null if not found or invalid. */
export function load<T>(key: string): T | null {
  const prefixedKey = STORAGE_PREFIX + key;
  const raw = localStorage.getItem(prefixedKey);

  if (raw === null) {
    return null;
  }

  try {
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}

/** Remove a value from local storage. */
export function remove(key: string): void {
  const prefixedKey = STORAGE_PREFIX + key;
  localStorage.removeItem(prefixedKey);
}

/** List all app keys in local storage (without prefix). */
export function listKeys(): string[] {
  const keys: string[] = [];

  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key?.startsWith(STORAGE_PREFIX)) {
      keys.push(key.slice(STORAGE_PREFIX.length));
    }
  }

  return keys;
}